import java.util.HashMap;

public class FibonacciDP {
    static int callsRecursive;
    static int callsMemo;

    public long fibRecursive(int n) {
        callsRecursive++;
        if (n <= 1) return n;
        return fibRecursive(n - 1) + fibRecursive(n - 2);
    }

    public long fibMemo(int n, HashMap<Integer, Long> memo) {
        callsMemo++;
        if (n <= 1) return n;
        // TODO: if memo contains n, return memo.get(n)
        // TODO: compute result = fibMemo(n-1, memo) + fibMemo(n-2, memo)
        // TODO: put result in memo and return it
        return 0;
    }

    public static void main(String[] args) {
        FibonacciDP fd = new FibonacciDP();

        callsRecursive = 0;
        long r1 = fd.fibRecursive(20);
        System.out.println("fib(20) recursive: " + r1 + ", calls: " + callsRecursive);

        callsMemo = 0;
        long r2 = fd.fibMemo(20, new HashMap<>());
        System.out.println("fib(20) memo:      " + r2 + ", calls: " + callsMemo);

        System.out.println("Speedup factor: " + (callsRecursive / callsMemo));
    }
}

import java.util.*;

public class ClimbingStairs {

    public int recursive(int n) {
        if (n <= 1) return 1;
        return recursive(n - 1) + recursive(n - 2);
    }

    public int memoized(int n, int[] memo) {
        if (n <= 1) return 1;
        if (memo[n] != 0) return memo[n];
        // TODO: memo[n] = memoized(n-1,memo) + memoized(n-2,memo); return memo[n]
        return 0;
    }

    public int tabulation(int n) {
        if (n <= 1) return 1;
        int[] dp = new int[n + 1];
        dp[0] = 1; dp[1] = 1;
        // TODO: for i from 2 to n: dp[i] = dp[i-1] + dp[i-2]
        return dp[n];
    }

    public static void main(String[] args) {
        ClimbingStairs cs = new ClimbingStairs();
        for (int n : new int[]{1, 4, 5, 10}) {
            int r  = cs.recursive(n);
            int m  = cs.memoized(n, new int[n+1]);
            int t  = cs.tabulation(n);
            System.out.printf("n=%2d: recursive=%d, memo=%d, tab=%d, same=%b%n",
                              n, r, m, t, r==m && m==t);
        }
    }
}

import java.util.Arrays;

public class MinCostPath {

    public int minCost(int[][] grid) {
        int m = grid.length, n = grid[0].length;
        int[][] dp = new int[m][n];
        dp[0][0] = grid[0][0];

        // Initialize first row (can only come from left)
        for (int j = 1; j < n; j++) dp[0][j] = dp[0][j-1] + grid[0][j];

        // Initialize first column (can only come from above)
        for (int i = 1; i < m; i++) dp[i][0] = dp[i-1][0] + grid[i][0];

        // TODO: Fill rest of dp table:
        //       dp[i][j] = grid[i][j] + min(dp[i-1][j], dp[i][j-1])

        return dp[m-1][n-1];
    }

    public static void main(String[] args) {
        MinCostPath mcp = new MinCostPath();
        int[][] grid = {
            {1, 3, 1},
            {1, 5, 1},
            {4, 2, 1}
        };
        System.out.println("Min cost: " + mcp.minCost(grid));

        int[][] grid2 = {
            {1, 2, 3},
            {4, 8, 2},
            {1, 5, 3}
        };
        System.out.println("Min cost 2: " + mcp.minCost(grid2));
    }
}
